const b = $json.body || $json;
const clean = (v) => (v ?? '').toString().trim();
const clientId = Number(clean(b.client_id));
const caseId = clean(b.case_id) ? Number(clean(b.case_id)) : null;
const starts = clean(b.starts_at);
const ends = clean(b.ends_at);
const valid = Number.isFinite(clientId) && starts !== '' && ends !== '';
return [{json:{
  valid,
  error: valid ? '' : 'Campos requeridos: client_id, starts_at, ends_at',
  client_id: clientId,
  case_id: Number.isFinite(caseId) ? caseId : null,
  starts_at: starts,
  ends_at: ends,
  location_type: clean(b.location_type) || 'virtual',
  meeting_link: clean(b.meeting_link) || null
}}];

